package com.cuzssp.campussecondhandtradingplatform_backend.mapper;import com.cuzssp.campussecondhandtradingplatform_backend.common.entity.Product;import org.apache.ibatis.annotations.*;import java.util.List;@Mapperpublic interface ProductMapper {    @Select("SELECT * FROM product WHERE id = #{id}")    Product selectById(@Param("id") Long id);    @Select("SELECT * FROM product")    List<Product> selectAll();    @Select("SELECT * FROM product WHERE status = 1 " +            "ORDER BY created_at DESC, price")    List<Product> selectAllActive();    @Select("SELECT * FROM product " +            "WHERE status = #{status} " +            "AND (title LIKE CONCAT('%',#{keyword},'%') " +            "OR description LIKE CONCAT('%',#{keyword},'%')) " +            "ORDER BY created_at DESC, price")    List<Product> searchByKeyword(@Param("keyword") String keyword, @Param("status") int status);    @Select("SELECT * FROM product " +            "WHERE status = #{status} AND category_id = #{categoryId} " +            "ORDER BY created_at DESC, price")    List<Product> selectByCategoryId(@Param("categoryId") Long categoryId, @Param("status") int status);    @Select("SELECT * FROM product " +            "WHERE status = #{status} AND campus = #{campus} " +            "ORDER BY created_at DESC, price")    List<Product> selectByCampus(@Param("campus") String campus, @Param("status") int status);    @Select("SELECT * FROM product " +            "WHERE user_id = #{userId} " +            "ORDER BY created_at DESC")    List<Product> selectByUserId(@Param("userId") Long userId);    @Select("SELECT * FROM product " +            "WHERE user_id = #{userId} AND status = #{status} " +            "ORDER BY created_at DESC")    List<Product> selectByUserIdAndStatus(@Param("userId") Long userId, @Param("status") Integer status);    @Select("SELECT * FROM product " +            "WHERE category_id = #{categoryId} AND campus = #{campus} AND status = #{status} " +            "ORDER BY created_at DESC")    List<Product> selectByCategoryAndCampus(            @Param("categoryId") Long categoryId,            @Param("campus") String campus,            @Param("status") int status);    @Select("SELECT COUNT(*) FROM product WHERE status = 1")    int countActive();    @Select("SELECT COUNT(*) FROM product")    int countAll();    @Select("SELECT COUNT(*) FROM product WHERE category_id = #{categoryId}")    int countByCategoryId(@Param("categoryId") Long categoryId);    @Insert("INSERT INTO product (user_id, category_id, title, description, " +            "price, original_price, `condition`, campus, status, view_count, created_at, updated_at) " +            "VALUES (#{userId}, #{categoryId}, #{title}, #{description}, " +            "#{price}, #{originalPrice}, #{condition}, #{campus}, #{status}, " +            "#{viewCount}, #{createdAt}, #{updatedAt})")    @Options(useGeneratedKeys = true, keyProperty = "id")    int insert(Product product);    @Update("UPDATE product " +            "SET title=#{title}, description=#{description}, price=#{price}, " +            "original_price=#{originalPrice}, `condition`=#{condition}, campus=#{campus}, " +            "category_id=#{categoryId}, status=#{status}, view_count=#{viewCount}, updated_at=#{updatedAt} " +            "WHERE id=#{id}")    int updateById(Product product);}